      function CF_TITEMPRESAFormula return VARCHAR2 is

   vTitEmpresa varchar2(80);
   vTexto      varchar2(80);

begin
   select tit_reportes 
   into   vTitEmpresa
   from   empresa
   where  cod_empresa = :pg_cOD_EMPRESA;

   return  upper(vTitEmpresa);
exception

   when SRW.NO_DATA_FOUND then

      select texto
      into   vTexto
      from   mensajes_sistema
      where  num_mensaje  = '000046'
        and  cod_sistema  = 'PA'
        and  cod_idioma   = :pg_coD_IDIOMA;

        SRW.message(0, 'PA-000046 ' || vTexto);
        raise SRW.program_abort;

end;

      function CF_TitSistemaFormula return VARCHAR2 is
   vTitSistema varchar2(80);
   vTexto      varchar2(80);
begin
   select  titulo
   into    vTitSistema
   from    titulos_sistemas
   where   cod_sistema = :pg_COD_SISTEMA
     and   cod_idioma  = :pg_COD_IDIOMA;

   return upper(vTitSistema);

exception

   when SRW.NO_DATA_FOUND then

      select texto
      into   vTexto
      from   mensajes_sistema
      where  num_mensaje  = '000048'
        and  cod_sistema  = 'PA'
        and  cod_idioma   = :pg_COD_IDIOMA;

        SRW.message(0, 'PA-000048 ' || vTexto);
        raise SRW.program_abort;

end;

      function CF_TitAgenciaFormula return VARCHAR2 is

   vTitAgencia varchar2(80);
   vTexto      varchar2(80);

begin

   select descripcion
   into   vTitAgencia
   from   agencia
   where  cod_empresa = :pg_COD_EMPRESA
     and  cod_agencia = :pg_COD_AGENCIA;

   return upper(vTitAgencia); 

exception

   when SRW.NO_DATA_FOUND then

      select texto
      into   vTexto
      from   mensajes_sistema
      where  num_mensaje  = '000045'
        and  cod_sistema  = 'PA'
        and  cod_idioma   = :pg_COD_IDIOMA;

        SRW.message(0, 'PA-000045 ' || vTexto);
        raise SRW.program_abort;
end;

      function CF_TitReporteFormula return VARCHAR2 is
   vTitReporte varchar2(200);
   vTexto      varchar2(200);

begin
   select titulo || ' Cliente: ' || :p_cod_cliente || ' ' || F_RET_NOM_CLIENTE(:p_cod_cliente)
   into   vTitReporte
   from   titulos_reportes
   where  nom_reporte = :pg_NOM_REPORTE
     and  cod_idioma  = :pg_COD_IDIOMA;

   return vTitReporte;

exception

   when SRW.NO_DATA_FOUND then

      select texto
      into   vTexto
      from   mensajes_sistema
      where  num_mensaje  = '000047'
        and  cod_sistema  = 'PA'
        and  cod_idioma   = :pg_COD_IDIOMA;

        SRW.message(0, 'PA-000047 ' || vTexto);
        raise SRW.program_abort;

end;

      function CF_TipocambioFormula return Number is
   v_tipcamb number(16,2);
   v_mensaje varchar2(100);
begin
    begin
		    Cg_Utl.Obtiene_TC_Conta(1, :sysdate, v_tipcamb, v_mensaje);
    exception
        when others then
          v_tipcamb := null;
    end;
    return v_tipcamb;
end;

      function BeforeReport return boolean is
	v_error varchar2(3000);
begin
  pr.Carga_Prr0402M(
        :p_cod_cliente,
        :p_fecha_hoy,
        v_error
    );
   IF v_error IS NOT NULL THEN
       return (FALSE);
    END IF;
  return (TRUE);
end;

      function M_LINEAS_WRAPFormatTrigger return boolean is
begin
  if nvl(:CS_LINEAS,0) > 0 then
    return (TRUE);
  else
    return (FALSE);
  end if;
end;

      function M_FL_WRAPFormatTrigger return boolean is
begin
  if nvl(:CS_FL,0) > 0 then
    return (TRUE);
  else
    return (FALSE);
  end if;
end;

      function M_IND_WRAPFormatTrigger return boolean is
begin
  if nvl(:CS_IND,0) > 0 then
    return (TRUE);
  else
    return (FALSE);
  end if;
end;

      function CF_TOT_DIRFormula return Number is
begin
  return NVL(:cs_tot_dir_bl, 0) + NVL(:cs_tot_dir_fl, 0) + NVL(:cs_sal_dir_ind, 0);
end;

      function CF_TOT_CONTFormula return Number is
begin
  return NVL(:cs_tot_cont_bl, 0) + NVL(:cs_tot_cont_fl, 0) + NVL(:cs_sal_cont_ind, 0);
end;

      function CF_PREV_DIRFormula return Number is
begin
  pr.pkg_obt_prevision.cargar(:cod_empresa, :p_cod_cliente, :p_fecha_hoy);
  return pr.pkg_obt_prevision.tot_prevision;
end;

      function CF_PREV_CONTFormula return Number is
begin
  pr.pkg_obt_prevision.cargar(:cod_empresa, :p_cod_cliente, :p_fecha_hoy);
  return pr.pkg_obt_prevision.tot_pre_con;
end;

      function CF_COD_CALIFFormula return varchar2 is
	v_calif varchar2(2);
begin
	begin
		SELECT cod_calif
		   into v_calif
		  FROM PR_CALIF_X_CLIENTE a
		  WHERE a.cod_empresa = :cod_empresa
		    AND a.cod_persona = :p_cod_cliente
			  AND a.fec_calif IN (SELECT  MAX(b.fec_calif)
		                          FROM PR_CALIF_X_CLIENTE b
		                   		    WHERE b.cod_empresa = :cod_empresa
		                      		  AND b.cod_persona = a.cod_persona);
	exception when no_data_found then
		v_calif := 'A';
	end;
	return v_calif;
end;

      function CF_CAEDECFormula return varchar2 is
	v_descripcion varchar2(150);
begin
	begin
		SELECT b.descripcion
			INTO v_descripcion
      	FROM cliente a, caedec b
      WHERE a.cod_actividad = cod_caedec
       AND a.cod_cliente = :p_cod_cliente
       AND a.cod_empresa = :cod_empresa;
  exception
   	     when no_data_found then
   	        v_descripcion := 'Sin CAEDEC';
   	     when too_many_rows then
   	        srw.message (0, 'Muchos Caedec');
  end;
  return v_descripcion;
end;

      function CF_NUM_IDFormula return Char is
begin
  return F_Tipo_Id(:p_cod_cliente);
end;

      function CF_DIRECFormula return Char is
begin
  return F_Direccion(:p_cod_cliente);
end;

      function CF_TELFormula return Number is
begin
  return F_Num_Telefono(:p_cod_cliente);
end;
